#include<bits/stdc++.h>
using namespace std;
int v[1010][1010];
int a[1010][1010],b[1010][1010];
int d[1010][1010],e[1010][1010];
int main()
{
    int r,c,n;
    scanf("%d%d%d",&r,&c,&n);
    for(int i=1;i<=r;i++)
    {
        for(int j=1;j<=c;j++)
        {
            scanf("%d",&v[i][j]);
        }
    }
    for(int i=1;i<=r;i++)
    {
        deque<int> q;
        for(int j=1;j<=c;j++)
        {
            while(!q.empty()&&v[i][q.back()]>=v[i][j])
            {
                q.pop_back();
            }
            q.push_back(j);
            while(!q.empty()&&q.front()<j-n+1)
            {
                q.pop_front();
            }
            a[i][j]=v[i][q.front()];
        }
    }
    for(int i=1;i<=c;i++)
    {
        deque<int> q;
        for(int j=1;j<=r;j++)
        {
            while(!q.empty()&&a[q.back()][i]>=a[j][i])
            {
                q.pop_back();
            }
            q.push_back(j);
            while(!q.empty()&&q.front()<j-n+1)
            {
                q.pop_front();
            }
            b[j][i]=a[q.front()][i];
        }
    }
    for(int i=1;i<=r;i++)
    {
        deque<int> q;
        for(int j=1;j<=c;j++)
        {
            while(!q.empty()&&v[i][q.back()]<=v[i][j])
            {
                q.pop_back();
            }
            q.push_back(j);
            while(!q.empty()&&q.front()<j-n+1)
            {
                q.pop_front();
            }
            d[i][j]=v[i][q.front()];
        }
    }
    for(int i=1;i<=c;i++)
    {
        deque<int> q;
        for(int j=1;j<=r;j++)
        {
            while(!q.empty()&&d[q.back()][i]<=d[j][i])
            {
                q.pop_back();
            }
            q.push_back(j);
            while(!q.empty()&&q.front()<j-n+1)
            {
                q.pop_front();
            }
            e[j][i]=d[q.front()][i];
        }
    }
