    //         printf("%d ",b[i][j]);
    //     }
    //     printf("\n");
    // }
    // printf("d:\n");
    // for(int i=1;i<=r;i++)
    // {
    //     for(int j=1;j<=c;j++)
    //     {
    //         printf("%d ",d[i][j]);
    //     }
    //     printf("\n");
    // }
    // printf("e:\n");
    // for(int i=1;i<=r;i++)
    // {
    //     for(int j=1;j<=c;j++)
    //     {
    //         printf("%d ",e[i][j]);
    //     }
    //     printf("\n");
    // }
    int ans=1e9;
    for(int i=n;i<=r;i++)
    {
        for(int j=n;j<=c;j++)
        {
            ans=min(ans,e[i][j]-b[i][j]);
        }
    }
    printf("%d",ans);
    return 0;
}
